using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x = 0, f = 1;
		char ch = gc();
		wh(ch < '0' || ch > '9')
		{
			if (ch == '-')f = -1;
			ch = getchar();
		}
		wh(ch >= '0' && ch <= '9')
		{
			x = x * 10 + ch - '0';
			ch = gc();
		}
		return x * f;
	}
	void write(ll x)
	{
		if (x < 0)pc('-'), x = -x;
		if (x > 9)write(x / 10);
		pc(x % 10 + '0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
long long n, d, r;
long long ha = 0, ans;
struct node
{
	long long hap;
	long long tim;
} a[50005];
bool check(long long x)
{
	long long j = 0;
	ha = 0;
	for (long long i = 1; i <= d; i++)
	{
		ha = ha >> 1;
		while (ha < x)
		{
			ha += a[++j].hap;
			if (j > n) return false;
			if (x && x == ans)a[j].tim = i;
		}
	}
	return 1;
}
signed main(void)
{
	cin >> n >> d;
	for (long long i = 1; i <= n; i++)
	{
		cin >> a[i].hap;
		r += a[i].hap;
	}
	long long l = 1;
	while (l <= r)
	{
		long long mid = (r + l) >> 1;
		if (check(mid))l = mid + 1, ans = mid;
		else r = mid - 1;
	}
	cout << ans << endl;
	check(ans);
	for (long long i = 1; i <= n; i++)
	{
		if (a[i].tim)printf("%lld\n", a[i].tim);
		else cout << d << "\n";
	}
	return false;
}
